import requests, json; base='http://127.0.0.1:5000'; rows=[]; add=lambda n,o,d='': rows.append((n,'PASS' if o else 'FAIL',d));

try:
 r=requests.get(base+'/',timeout=5); add('PAGE /', r.status_code==200, f'HTTP {r.status_code}')
except Exception as e:
 add('PAGE /', False, str(e))

try:
 r=requests.get(base+'/projects',timeout=5); add('PAGE /projects', r.status_code==200, f'HTTP {r.status_code}')
except Exception as e:
 add('PAGE /projects', False, str(e))

try:
 r=requests.get(base+'/settings',timeout=5); add('PAGE /settings', r.status_code==200, f'HTTP {r.status_code}')
except Exception as e:
 add('PAGE /settings', False, str(e))

try:
 r=requests.get(base+'/api/settings',timeout=5); j=r.json(); add('GET /api/settings', r.ok and j.get('success') is True, f"theme={j.get('settings',{}).get('theme')}")
except Exception as e:
 add('GET /api/settings', False, str(e))

try:
 payload={'theme':'light','show_animations':False,'compact_mode':True,'waveform_colors':'vibrant','accent_color':'#ff0000'}; p=requests.post(base+'/api/settings',json=payload,timeout=5); g=requests.get(base+'/api/settings',timeout=5).json().get('settings',{}); ok=(p.ok and g.get('theme')=='light' and g.get('show_animations') is False and g.get('compact_mode') is True and g.get('waveform_colors')=='vibrant' and g.get('accent_color')=='#0f766e'); add('POST /api/settings persistence', ok, json.dumps({k:g.get(k) for k in ['theme','show_animations','compact_mode','waveform_colors','accent_color']}))
except Exception as e:
 add('POST /api/settings persistence', False, str(e))

try:
 r=requests.get(base+'/api/storage-info',timeout=5); j=r.json(); add('GET /api/storage-info', r.ok and j.get('success') is True and 'used_mb' in j and 'project_count' in j, f"used_mb={j.get('used_mb')}, projects={j.get('project_count')}")
except Exception as e:
 add('GET /api/storage-info', False, str(e))

try:
 r=requests.post(base+'/api/clear-cache',timeout=5); j=r.json(); add('POST /api/clear-cache', r.ok and j.get('success') is True, f"removed={j.get('removed')}")
except Exception as e:
 add('POST /api/clear-cache', False, str(e))

try:
 requests.post(base+'/api/settings',json={'theme':'dark','show_animations':True,'compact_mode':False,'waveform_colors':'default'},timeout=5); g=requests.get(base+'/api/settings',timeout=5).json().get('settings',{}); ok=(g.get('theme')=='dark' and g.get('show_animations') is True and g.get('compact_mode') is False and g.get('waveform_colors')=='default'); add('Restore baseline settings', ok, json.dumps({k:g.get(k) for k in ['theme','show_animations','compact_mode','waveform_colors','accent_color']}))
except Exception as e:
 add('Restore baseline settings', False, str(e))

print('\n'.join([f"{s:<4} | {n:<32} | {d}" for n,s,d in rows])); print('\nOVERALL:', 'PASS' if all(s=='PASS' for _,s,_ in rows) else 'FAIL')
